<?php
declare(strict_types=1);namespace App\Services\ControlEscaneres\Shared;use App\DTO\ControlEscaneres\InspectionDifference;
final class InspectionComparisonService implements InspectionComparisonServiceInterface{private const RANK=['no funciona'=>0,'faltante'=>0,'dañado'=>1,'regular'=>2,'bueno'=>3,'excelente'=>4,'no aplica'=>null];public function compare(array$d,array$r):array{$left=[];foreach($d as$x)$left[$x['componente']]=$x;$out=[];foreach($r as$x){$old=$left[$x['componente']]??null;$result='sin_referencia';if($old){$a=self::RANK[mb_strtolower($old['estado'])]??null;$b=self::RANK[mb_strtolower($x['estado'])]??null;if($old['estado']===$x['estado'])$result='igual';elseif($a===null||$b===null)$result='no_comparable';elseif($b>$a)$result='mejoro';else$result='empeoro';if(isset($old['valor_numerico'],$x['valor_numerico'])&&$old['valor_numerico']!==null&&$x['valor_numerico']!==null)$result=$x['valor_numerico']==$old['valor_numerico']?'igual':($x['valor_numerico']>$old['valor_numerico']?'mejoro':'empeoro');}$out[]=new InspectionDifference($x['componente'],$old,$x,$result);}return$out;}}
